import java.io.IOException;
import java.io.PrintWriter;

import javax.servlet.ServletException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

import org.owasp.esapi.ESAPI;

public class SecureServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        String userInput = request.getParameter("input");

        out.println("<html>");
        out.println("<head><title>XSS Prevention Example</title></head>");
        out.println("<body>");
        out.println("<h1>User Input:</h1>");

        // Sanitize and escape user input using ESAPI encoder
        String safeUserInput = ESAPI.encoder().encodeForHTML(userInput);

        out.println("<p>" + safeUserInput + "</p>"); // User input is now properly sanitized

